export const getGetStoresQueryKey = () => {
  return [`/api/stores`] as const;
};

export const getGetStoresQueryOptions = <
  TData = Awaited<ReturnType<typeof getStores>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<Awaited<ReturnType<typeof getStores>>, TError, TData>;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetStoresQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getStores>>> = ({
    signal,
  }) => getStores({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getStores>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetStoresQueryResult = NonNullable<
  Awaited<ReturnType<typeof getStores>>
>;
export type GetStoresQueryError = ErrorType<unknown>;

/**
 * @summary Get active stores
 */

export function useGetStores<
  TData = Awaited<ReturnType<typeof getStores>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<Awaited<ReturnType<typeof getStores>>, TError, TData>;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetStoresQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Validate a discount code
 */
export const getValidateDiscountUrl = () => {
  return `/api/discounts/validate`;
};

export const validateDiscount = async (
  validateDiscountRequest: ValidateDiscountRequest,
  options?: RequestInit,
): Promise<DiscountValidation> => {
  return customFetch<DiscountValidation>(getValidateDiscountUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(validateDiscountRequest),
  });
};

export const getValidateDiscountMutationOptions = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof validateDiscount>>,
    TError,
    { data: BodyType<ValidateDiscountRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof validateDiscount>>,
  TError,
  { data: BodyType<ValidateDiscountRequest> },
  TContext
> => {
  const mutationKey = ["validateDiscount"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof validateDiscount>>,
    { data: BodyType<ValidateDiscountRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return validateDiscount(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ValidateDiscountMutationResult = NonNullable<
  Awaited<ReturnType<typeof validateDiscount>>
>;
export type ValidateDiscountMutationBody = BodyType<ValidateDiscountRequest>;
export type ValidateDiscountMutationError = ErrorType<ErrorResponse>;

/**
 * @summary Validate a discount code
 */
export const useValidateDiscount = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof validateDiscount>>,
    TError,
    { data: BodyType<ValidateDiscountRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof validateDiscount>>,
  TError,
  { data: BodyType<ValidateDiscountRequest> },
  TContext
> => {
  return useMutation(getValidateDiscountMutationOptions(options));
};
